/*
 * cosh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly cosh  (test_cosh_opt.elf)
 *   2. Linked with toolchain's default cosh        (test_cosh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += cosh(vx);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    double r = cosh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for cosh()      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                  /* 2^-1022, smallest normal */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                  /* largest normal: 0x7fefffffffffffff */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX itself (same as -1 below is covered via -DBL_MAX) */

    /* --- Section 4: Near 1.0 - highest ULP density for normal inputs (8) --- */
    emit_u(0x3feffffffffffffful);   /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3feffffffffffff0ULL);  /* several ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);  /* several ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfeffffffffffffful);   /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fdffffffffffffful);   /* one ULP below 0.5 */
    emit(0.5);
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit(2.0);
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Known mathematical values (14) --- */
    emit(0.1);
    emit(-0.1);
    emit(0.5);                      /* cosh(0.5) ~ 1.1276 */
    emit(-0.5);
    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: cosh(ln2) = 1.25 */
    emit(-0.693147180559945);       /* -ln2 */
    emit(1.5);
    emit(-1.5);
    emit(2.718281828459045);        /* e: cosh(e) ~ 7.6101 */
    emit(-2.718281828459045);
    emit(5.0);
    emit(-5.0);
    emit(10.0);
    emit(-10.0);

    /* --- Section 7: Overflow threshold stress (8) --- */
    /* cosh(x) overflows when x > ln(2*DBL_MAX) ~ 710.4758 */
    emit(709.0);
    emit(-709.0);
    emit(709.7827128933840);        /* ln(DBL_MAX): cosh ~ DBL_MAX/2 */
    emit(-709.7827128933840);
    emit(710.0);
    emit(-710.0);
    emit(710.4758);                 /* just below overflow for cosh */
    emit(711.0);                    /* overflow -> +Inf */

    /* --- Section 8: ULP neighbors of cosh overflow threshold (6) --- */
    /* 710.4758 in double, scanning near the boundary bit-by-bit */
    emit_u(0x4086232bdd7abcd2ULL);  /* ~710.4758: just below cosh overflow */
    emit_u(0x4086232bdd7abcd3ULL);  /* one ULP above */
    emit_u(0x4086232bdd7abcd1ULL);  /* one ULP below */
    emit_u(0x40862e42fefa39efULL);  /* exp overflow threshold ~709.78 */
    emit_u(0x40862e42fefa39f0ULL);  /* one ULP above exp overflow threshold */
    emit_u(0x40862e42fefa39eeULL);  /* one ULP below exp overflow threshold */

    /* --- Section 9: Small-argument fast-path thresholds (8) --- */
    /* cosh(x) ~ 1 + x^2/2 for small x; test at power-of-2 thresholds */
    emit_u(0x3fb0000000000000ULL);  /* 2^-12: threshold for linear approx */
    emit_u(0xbfb0000000000000ULL);  /* -2^-12 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26: deeper in the tiny region */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3c90000000000000ULL);  /* 2^-54: below 1 ULP of 1.0 */
    emit_u(0xbc90000000000000ULL);  /* -2^-54 */

    /* --- Section 10: Hard cases and medium range (31) --- */
    /* Integer powers of 2 */
    emit(4.0);
    emit(-4.0);
    emit(8.0);
    emit(-8.0);
    emit(16.0);
    emit(-16.0);
    emit(32.0);
    emit(-32.0);
    emit(64.0);
    emit(-64.0);
    /* Half-integers */
    emit(1.5);                      /* duplicate intentionally skipped; use 2.5 */
    emit(2.5);
    emit(-2.5);
    emit(4.5);
    emit(-4.5);
    emit(8.5);
    emit(-8.5);
    /* ln2 multiples: cosh has known values */
    emit(1.3862943611198906);       /* 2*ln2: cosh(2*ln2) = 17/8 = 2.125 */
    emit(-1.3862943611198906);
    emit(2.0794415416798357);       /* 3*ln2 */
    emit(-2.0794415416798357);
    /* Medium range */
    emit(20.0);
    emit(-20.0);
    emit(50.0);
    emit(-50.0);
    emit(100.0);
    emit(-100.0);
    emit(500.0);
    emit(-500.0);
    emit(3.0);
    emit(-3.0);
    emit(0.25);
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 100] in 100 steps and [-100, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-100, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

